package ru.memearena.scout.application; import org.springframework.dao.DataIntegrityViolationException; import org.springframework.stereotype.Service; import ru.memearena.scout.domain.*; import ru.memearena.scout.infrastructure.*; import java.time.*; import java.util.*; @Service public class AchievementService{ public record Def(String code,String title,String description){} public static final Map<String,Def> CATALOG=Map.ofEntries(Map.entry("FIRST_VOTE",new Def("FIRST_VOTE","Первый голос","Ты сделал первый выбор")),Map.entry("FIRST_PREDICTION",new Def("FIRST_PREDICTION","Первый прогноз","Ты поддержал мем на ранней стадии")),Map.entry("FIRST_HIT",new Def("FIRST_HIT","Первое попадание","Ты впервые угадал будущий мем-хит")),Map.entry("EARLY_BIRD",new Def("EARLY_BIRD","Ранняя пташка","Успешный прогноз в первый час")),Map.entry("STREAK_3",new Def("STREAK_3","Серия 3","Три успешных прогноза подряд")),Map.entry("STREAK_10",new Def("STREAK_10","Серия 10","Десять успешных прогнозов подряд")),Map.entry("SCOUT_RANK",new Def("SCOUT_RANK","Мемный скаут","Достигнут ранг скаута")),Map.entry("TREND_HUNTER_RANK",new Def("TREND_HUNTER_RANK","Охотник за трендами","Достигнут ранг охотника")),Map.entry("MEME_ORACLE_RANK",new Def("MEME_ORACLE_RANK","Мемный оракул","Достигнут ранг оракула")),Map.entry("VOTER_100",new Def("VOTER_100","100 голосов","Ты сделал 100 голосов"))); private final UserAchievementRepository repo; public AchievementService(UserAchievementRepository repo){this.repo=repo;} public void unlock(UUID user,String code,Instant now){try{ if(!repo.existsByUserIdAndAchievementCode(user,code)) repo.save(new UserAchievement(UUID.randomUUID(),user,code,now,null));}catch(DataIntegrityViolationException ignored){}} public List<UserAchievement> byUser(UUID u){return repo.findByUserIdOrderByUnlockedAtDesc(u);} }
